INSERT INTO public.kudos VALUES (884, 'Mei-Lin Wu', 'William Tanaka', 'sim', '440', 'Thanks for creating a written guide on how to navigate blockers when you''re new and don''t yet know who to ask.', '2026-07-06 00:00:00-06', '2026-07-06 00:00:00-06', NULL, NULL, false);
INSERT INTO public.kudos VALUES (805, 'William Tanaka', 'Omar Haddad', 'sim', '361', 'Thanks for organizing the collaborative sprint planning between the platform and product teams to sequence the work correctly.', '2026-06-15 00:00:00-06', '2026-06-15 00:00:00-06', 884, NULL, false);
INSERT INTO public.kudos VALUES (885, 'Omar Haddad', 'Daniel Moreau', 'sim', '441', 'Really appreciate you setting up the team language guide to encourage positive framing in our communication.', '2026-07-06 00:00:00-06', '2026-07-06 00:00:00-06', NULL, NULL, false);
INSERT INTO public.kudos VALUES (841, 'Daniel Moreau', 'Omar Haddad', 'sim', '397', 'Really appreciate you explaining our deprecation policy and how we handle removing old features to the new engineer.', '2026-06-22 00:00:00-06', '2026-06-22 00:00:00-06', 885, NULL, false);
INSERT INTO public.kudos VALUES (886, 'William Tanaka', 'Maria Santos', 'sim', '442', 'Appreciate you posting the positive NPS survey results with shout-outs to the individuals whose work drove them.', '2026-07-06 00:00:00-06', '2026-07-06 00:00:00-06', NULL, NULL, false);
INSERT INTO public.kudos VALUES (807, 'Maria Santos', 'Omar Haddad', 'sim', '363', 'Thanks for explaining how to configure our service to handle graceful shutdowns when Kubernetes sends a SIGTERM.', '2026-06-15 00:00:00-06', '2026-06-15 00:00:00-06', 886, NULL, false);
